  '{"id":"uncertainty","term":"Analytical uncertainty","family":"Measurement practice","equation":"reported value +/- uncertainty","definition":"The bounded doubt attached to a measurement, assignment or calculated quantity.","academicUse":"Use it to avoid overstating spectral assignments, concentration calculations and route comparisons.","evidenceNote":"State whether uncertainty is instrumental, procedural, interpretive or statistical.","sourceRefs":["nist-webbook","iupac-goldbook"]}',
