) VALUES (
  'concept:mechanism-evidence-stack',
  'mechanism-evidence-stack',
  'concept',
  'Concept',
  'Mechanism evidence stack',
  'Mechanistic reasoning',
  'A layered way to describe how multiple measurements constrain plausible reaction mechanisms. | kinetics + isotope effects + stereochemistry + intermediates + controls -> mechanism argument | No single measurement normally proves a mechanism; it narrows alternatives.',
  '',
  'Mechanistic reasoning',
  '',
  0,
  '',
  '[]',
  'record.html?type=concept&id=mechanism-evidence-stack',
  'library.html?q=Mechanism%20evidence%20stack',
