INSERT OR REPLACE INTO records (
  record_key, id, type, type_label, title, subtitle, body, domain, family, risk,
  maturity, formula, tags_json, href, source_href, image_url, raw_json, search_text
) VALUES (
  'research-case:unknown-carbonyl',
  'unknown-carbonyl',
  'research-case',
  'Research case',
  'Unknown carbonyl assignment',
  'Spectroscopy and organic structure',
  'Does the evidence support assigning the unknown as an aldehyde rather than a ketone? | The combined IR, 1H NMR and 13C NMR pattern supports an aldehyde assignment, with the strongest single observation being the downfield 1H signal near 9.8 ppm.',
  'Spectroscopy and organic structure',
  '',
  '',
  0,
  '',
  '[]',
  'record.html?type=research-case&id=unknown-carbonyl',
  'research.html?case=unknown-carbonyl',
  'data:image/svg+xml;charset=UTF-8,%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22640%22%20height%3D%22420%22%20viewBox%3D%220%200%20640%20420%22%3E%3Crect%20width%3D%22640%22%20height%3D%22420%22%20fill%3D%22%23f5f5f7%22%2F%3E%3Cpath%20d%3D%22M84%20278%20190%2096l106%20182H84Zm260-152h170v170H344V126Zm-174%2044h276%22%20fill%3D%22none%22%20stroke%3D%22%230071e3%22%20stroke-width%3D%2212%22%20stroke-linecap%3D%22round%22%20stroke-linejoin%3D%22round%22%20opacity%3D%22.34%22%2F%3E%3Ccircle%20cx%3D%22190%22%20cy%3D%2296%22%20r%3D%2220%22%20fill%3D%22%2386868b%22%2F%3E%3Ccircle%20cx%3D%22296%22%20cy%3D%22278%22%20r%3D%2220%22%20fill%3D%22%2386868b%22%2F%3E%3Ccircle%20cx%3D%22514%22%20cy%3D%22126%22%20r%3D%2218%22%20fill%3D%22%2386868b%22%2F%3E%3Ctext%20x%3D%2242%22%20y%3D%2258%22%20fill%3D%22%231d1d1f%22%20font-family%3D%22-apple-system%2CBlinkMacSystemFont%2CSegoe%20UI%2CArial%2Csans-serif%22%20font-size%3D%2224%22%20font-weight%3D%22700%22%3EResearch%20case%3C%2Ftext%3E%3Ctext%20x%3D%2242%22%20y%3D%22355%22%20fill%3D%22%231d1d1f%22%20font-family%3D%22-apple-system%2CBlinkMacSystemFont%2CSegoe%20UI%2CArial%2Csans-serif%22%20font-size%3D%2236%22%20font-weight%3D%22800%22%3EUnknown%20carbonyl%20assignment%3C%2Ftext%3E%3Ctext%20x%3D%2242%22%20y%3D%22388%22%20fill%3D%22%236e6e73%22%20font-family%3D%22-apple-system%2CBlinkMacSystemFont%2CSegoe%20UI%2CArial%2Csans-serif%22%20font-size%3D%2220%22%20font-weight%3D%22600%22%3ESpectroscopy%20and%20organic%20structure%3C%2Ftext%3E%3C%2Fsvg%3E',
  '{"id":"unknown-carbonyl","title":"Unknown carbonyl assignment","discipline":"Spectroscopy and organic structure","question":"Does the evidence support assigning the unknown as an aldehyde rather than a ketone?","thesis":"The combined IR, 1H NMR and 13C NMR pattern supports an aldehyde assignment, with the strongest single observation being the downfield 1H signal near 9.8 ppm.","confidence":88,"sourceRefs":["iupac-beer","nist-webbook","iupac-goldbook"],"observations":[{"type":"IR","level":"A","observation":"Strong absorption at 1718 cm-1.","inference":"Consistent with a carbonyl functional group.","limitation":"The band alone does not distinguish aldehyde from ketone, ester or acid."},{"type":"1H NMR","level":"A","observation":"One-proton resonance at delta 9.8 ppm.","inference":"Strong evidence for an aldehydic proton.","limitation":"Confirm integration and rule out impurity or solvent artefact."},{"type":"13C NMR","level":"A","observation":"Carbon signal near delta 200 ppm.","inference":"Consistent with aldehyde or ketone carbonyl carbon.","limitation":"Requires correlation with proton NMR for aldehyde-specific assignment."},{"type":"Method","level":"C","observation":"Assignment uses converging spectral evidence rather than one diagnostic peak.","inference":"The claim has stronger academic defensibility.","limitation":"Reference spectra or authentic sample comparison would increase confidence."}],"argument":{"claim":"The unknown contains an aldehyde carbonyl.","warrant":"Aldehydes commonly show both a carbonyl signal and a distinctive downfield proton resonance; a ketone would lack the aldehydic 1H signal.","counter":"A single IR carbonyl absorption is insufficient because many carbonyl derivatives absorb in similar regions.","nextTest":"Acquire 2D NMR or compare against a reference spectrum from an evaluated database."},"report":{"aim":"Assign the most plausible carbonyl class from the available spectral data.","method":"Compare observed IR, 1H NMR and 13C NMR features against curated reference ranges and record limitations.","conclusion":"The spectral pattern supports aldehyde assignment, with the aldehydic proton providing the discriminating evidence.","limitations":"No authentic sample comparison, no 2D NMR, and no purity assessment are included in this static case file."}}',
  'research-case research case unknown carbonyl assignment spectroscopy and organic structure does the evidence support assigning the unknown as an aldehyde rather than a ketone the combined ir 1h nmr and 13c nmr pattern supports an aldehyde assignment with the strongest single observation being the downfield 1h signal near 9.8 ppm. spectroscopy and organic structure question does the evidence support assigning the unknown as an aldehyde rather than a ketone thesis the combined ir 1h nmr and 13c nmr pattern supports an aldehyde assignment with the strongest single observation being the downfield 1h signal near 9.8 ppm. evidence techniques limitations'
);
