) VALUES (
  'research-case:green-route',
  'green-route',
  'research-case',
  'Research case',
  'Green metric route comparison',
  'Sustainability and lab reporting',
  'How should a route be evaluated when yield and hazard point in different directions? | A more academic comparison reports yield, selectivity, waste boundary and hazard rather than ranking routes by percentage yield alone.',
  'Sustainability and lab reporting',
  '',
  '',
  0,
  '',
  '[]',
  'record.html?type=research-case&id=green-route',
  'research.html?case=green-route',
  'data:image/svg+xml;charset=UTF-8,%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22640%22%20height%3D%22420%22%20viewBox%3D%220%200%20640%20420%22%3E%3Crect%20width%3D%22640%22%20height%3D%22420%22%20fill%3D%22%23f5f5f7%22%2F%3E%3Cpath%20d%3D%22M84%20278%20190%2096l106%20182H84Zm260-152h170v170H344V126Zm-174%2044h276%22%20fill%3D%22none%22%20stroke%3D%22%230071e3%22%20stroke-width%3D%2212%22%20stroke-linecap%3D%22round%22%20stroke-linejoin%3D%22round%22%20opacity%3D%22.34%22%2F%3E%3Ccircle%20cx%3D%22190%22%20cy%3D%2296%22%20r%3D%2220%22%20fill%3D%22%2386868b%22%2F%3E%3Ccircle%20cx%3D%22296%22%20cy%3D%22278%22%20r%3D%2220%22%20fill%3D%22%2386868b%22%2F%3E%3Ccircle%20cx%3D%22514%22%20cy%3D%22126%22%20r%3D%2218%22%20fill%3D%22%2386868b%22%2F%3E%3Ctext%20x%3D%2242%22%20y%3D%2258%22%20fill%3D%22%231d1d1f%22%20font-family%3D%22-apple-system%2CBlinkMacSystemFont%2CSegoe%20UI%2CArial%2Csans-serif%22%20font-size%3D%2224%22%20font-weight%3D%22700%22%3EResearch%20case%3C%2Ftext%3E%3Ctext%20x%3D%2242%22%20y%3D%22355%22%20fill%3D%22%231d1d1f%22%20font-family%3D%22-apple-system%2CBlinkMacSystemFont%2CSegoe%20UI%2CArial%2Csans-serif%22%20font-size%3D%2236%22%20font-weight%3D%22800%22%3EGreen%20metric%20route%20compariso%3C%2Ftext%3E%3Ctext%20x%3D%2242%22%20y%3D%22388%22%20fill%3D%22%236e6e73%22%20font-family%3D%22-apple-system%2CBlinkMacSystemFont%2CSegoe%20UI%2CArial%2Csans-serif%22%20font-size%3D%2220%22%20font-weight%3D%22600%22%3ESustainability%20and%20lab%20reporting%3C%2Ftext%3E%3C%2Fsvg%3E',
  '{"id":"green-route","title":"Green metric route comparison","discipline":"Sustainability and lab reporting","question":"How should a route be evaluated when yield and hazard point in different directions?","thesis":"A more academic comparison reports yield, selectivity, waste boundary and hazard rather than ranking routes by percentage yield alone.","confidence":76,"sourceRefs":["acs-green","orgsyn","pubchem"],"observations":[{"type":"Metric","level":"D","observation":"Yield measures desired product relative to theoretical amount.","inference":"Yield does not account for solvent, auxiliary reagents or purification burden.","limitation":"Yield remains important, but it is incomplete."},{"type":"Metric","level":"D","observation":"E-factor considers waste mass relative to product mass.","inference":"A lower E-factor can identify a cleaner route even when yields are similar.","limitation":"Boundary definitions must be stated."},{"type":"Hazard","level":"D","observation":"Hazardous reagents and solvents change the risk profile.","inference":"Academic route choice should include safety and sustainability language.","limitation":"Full assessment requires SDS and institutional controls."}],"argument":{"claim":"Route evaluation should combine yield, selectivity, hazard and waste metrics.","warrant":"A single percentage yield can hide poor atom economy, hazardous conditions or heavy purification waste.","counter":"At discovery scale, data may be incomplete; report assumptions instead of overclaiming.","nextTest":"Calculate yield, atom economy and E-factor with clearly defined mass boundaries."},"report":{"aim":"Compare routes using a defensible sustainability framework.","method":"State yield, waste boundary, hazardous inputs, purification burden and evidence level for each claim.","conclusion":"The academically stronger route argument is multi-criterion, not yield-only.","limitations":"The static example does not include full inventory masses or SDS-specific hazard coding."}}',
  'research-case research case green metric route comparison sustainability and lab reporting how should a route be evaluated when yield and hazard point in different directions a more academic comparison reports yield selectivity waste boundary and hazard rather than ranking routes by percentage yield alone. sustainability and lab reporting question how should a route be evaluated when yield and hazard point in different directions thesis a more academic comparison reports yield selectivity waste boundary and hazard rather than ranking routes by percentage yield alone. evidence techniques limitations'
);
