  0,
  '',
  '["IR","1H NMR","13C NMR","carbonyl","assignment"]',
  'record.html?type=dossier&id=carbonyl-forensics',
  'dossiers.html?id=carbonyl-forensics',
  'data:image/svg+xml;charset=UTF-8,%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22640%22%20height%3D%22420%22%20viewBox%3D%220%200%20640%20420%22%3E%3Crect%20width%3D%22640%22%20height%3D%22420%22%20fill%3D%22%23f5f5f7%22%2F%3E%3Cpath%20d%3D%22M84%20278%20190%2096l106%20182H84Zm260-152h170v170H344V126Zm-174%2044h276%22%20fill%3D%22none%22%20stroke%3D%22%231d1d1f%22%20stroke-width%3D%2212%22%20stroke-linecap%3D%22round%22%20stroke-linejoin%3D%22round%22%20opacity%3D%22.34%22%2F%3E%3Ccircle%20cx%3D%22190%22%20cy%3D%2296%22%20r%3D%2220%22%20fill%3D%22%230071e3%22%2F%3E%3Ccircle%20cx%3D%22296%22%20cy%3D%22278%22%20r%3D%2220%22%20fill%3D%22%230071e3%22%2F%3E%3Ccircle%20cx%3D%22514%22%20cy%3D%22126%22%20r%3D%2218%22%20fill%3D%22%230071e3%22%2F%3E%3Ctext%20x%3D%2242%22%20y%3D%2258%22%20fill%3D%22%231d1d1f%22%20font-family%3D%22-apple-system%2CBlinkMacSystemFont%2CSegoe%20UI%2CArial%2Csans-serif%22%20font-size%3D%2224%22%20font-weight%3D%22700%22%3EDossier%3C%2Ftext%3E%3Ctext%20x%3D%2242%22%20y%3D%22355%22%20fill%3D%22%231d1d1f%22%20font-family%3D%22-apple-system%2CBlinkMacSystemFont%2CSegoe%20UI%2CArial%2Csans-serif%22%20font-size%3D%2236%22%20font-weight%3D%22800%22%3ECarbonyl%20Forensics%20Dossier%3C%2Ftext%3E%3Ctext%20x%3D%2242%22%20y%3D%22388%22%20fill%3D%22%236e6e73%22%20font-family%3D%22-apple-system%2CBlinkMacSystemFont%2CSegoe%20UI%2CArial%2Csans-serif%22%20font-size%3D%2220%22%20font-weight%3D%22600%22%3ESpectroscopy%20and%20structure%20proof%20%C2%B7%20active%3C%2Ftext%3E%3C%2Fsvg%3E',
  '{"id":"carbonyl-forensics","title":"Carbonyl Forensics Dossier","field":"Spectroscopy and structure proof","status":"active","maturity":86,"abstract":"A structured case file for distinguishing aldehydes, ketones and acyl derivatives by converging IR, 1H NMR, 13C NMR and mass-spectral evidence.","keywords":["IR","1H NMR","13C NMR","carbonyl","assignment"],"methods":["Triangulated spectral assignment","Reference-range comparison","Impurity and artefact audit"],"observables":["IR carbonyl region between 1680 and 1750 cm-1","Downfield 1H NMR evidence near 9-10.5 ppm","13C carbonyl resonance and isotope-pattern checks"],"claims":["Aldehyde assignment requires evidence beyond an IR carbonyl band.","Converging spectra are stronger than a single diagnostic peak.","Reference comparison should include solvent, concentration and purity context."],"limitations":["No two-dimensional NMR is embedded in the static prototype.","Reference ranges are pedagogic summaries rather than full spectra.","Authentic sample comparison remains the strongest confirmatory step."],"reproducibility":[{"item":"Units recorded","state":"complete"},{"item":"Source family linked","state":"complete"},{"item":"Raw spectra archived","state":"missing"},{"item":"Purity statement","state":"partial"}],"linked":[{"label":"Open Research Desk case","href":"research.html?case=unknown-carbonyl"},{"label":"Open Spectroscopy concept","href":"library.html?q=chemical%20shift"}]}',
  'dossier dossier carbonyl forensics dossier spectroscopy and structure proof active a structured case file for distinguishing aldehydes ketones and acyl derivatives by converging ir 1h nmr 13c nmr and mass-spectral evidence. aldehyde assignment requires evidence beyond an ir carbonyl band. converging spectra are stronger than a single diagnostic peak. reference comparison should include solvent concentration and purity context. spectroscopy and structure proof ir 1h nmr 13c nmr carbonyl assignment summary a structured case file for distinguishing aldehydes ketones and acyl derivatives by converging ir 1h nmr 13c nmr and mass-spectral evidence. highlights claims aldehyde assignment requires evidence beyond an ir carbonyl band. converging spectra are stronger than a single diagnostic peak. reference comparison should include solvent concentration and purity context. references'
);
