  'record.html?type=method&id=claim-audit',
  'methods.html?id=claim-audit',
  'data:image/svg+xml;charset=UTF-8,%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22640%22%20height%3D%22420%22%20viewBox%3D%220%200%20640%20420%22%3E%3Crect%20width%3D%22640%22%20height%3D%22420%22%20fill%3D%22%23f5f5f7%22%2F%3E%3Cpath%20d%3D%22M84%20278%20190%2096l106%20182H84Zm260-152h170v170H344V126Zm-174%2044h276%22%20fill%3D%22none%22%20stroke%3D%22%231d1d1f%22%20stroke-width%3D%2212%22%20stroke-linecap%3D%22round%22%20stroke-linejoin%3D%22round%22%20opacity%3D%22.34%22%2F%3E%3Ccircle%20cx%3D%22190%22%20cy%3D%2296%22%20r%3D%2220%22%20fill%3D%22%230071e3%22%2F%3E%3Ccircle%20cx%3D%22296%22%20cy%3D%22278%22%20r%3D%2220%22%20fill%3D%22%230071e3%22%2F%3E%3Ccircle%20cx%3D%22514%22%20cy%3D%22126%22%20r%3D%2218%22%20fill%3D%22%230071e3%22%2F%3E%3Ctext%20x%3D%2242%22%20y%3D%2258%22%20fill%3D%22%231d1d1f%22%20font-family%3D%22-apple-system%2CBlinkMacSystemFont%2CSegoe%20UI%2CArial%2Csans-serif%22%20font-size%3D%2224%22%20font-weight%3D%22700%22%3EMethod%3C%2Ftext%3E%3Ctext%20x%3D%2242%22%20y%3D%22355%22%20fill%3D%22%231d1d1f%22%20font-family%3D%22-apple-system%2CBlinkMacSystemFont%2CSegoe%20UI%2CArial%2Csans-serif%22%20font-size%3D%2236%22%20font-weight%3D%22800%22%3EClaim%20Audit%20Protocol%3C%2Ftext%3E%3Ctext%20x%3D%2242%22%20y%3D%22388%22%20fill%3D%22%236e6e73%22%20font-family%3D%22-apple-system%2CBlinkMacSystemFont%2CSegoe%20UI%2CArial%2Csans-serif%22%20font-size%3D%2220%22%20font-weight%3D%22600%22%3EAcademic%20reasoning%20%C2%B7%20Core%3C%2Ftext%3E%3C%2Fsvg%3E',
  '{"id":"claim-audit","title":"Claim Audit Protocol","domain":"Academic reasoning","level":"Core","summary":"Converts an informal chemistry statement into a testable claim with evidence type, source family, limitation and next validation step.","inputs":["Proposed claim","Evidence item","Source family","Known limitation"],"outputs":["Claim boundary","Evidence grade","Counterargument","Next experiment"],"checklist":["The claim is written as a chemical assertion rather than a topic heading.","A source family is attached to the evidence, not just listed at the end.","A limitation is included before the conclusion is strengthened.","Units, solvent, phase, temperature or substrate class are recorded where relevant."],"example":"Do not write ''PCC oxidizes alcohols.'' Write ''PCC is commonly used for selective oxidation of many primary alcohols to aldehydes under anhydrous textbook conditions; substrate-specific procedure evidence is still required.''"}',
