  'data:image/svg+xml;charset=UTF-8,%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22640%22%20height%3D%22420%22%20viewBox%3D%220%200%20640%20420%22%3E%3Crect%20width%3D%22640%22%20height%3D%22420%22%20fill%3D%22%23f5f5f7%22%2F%3E%3Cpath%20d%3D%22M84%20278%20190%2096l106%20182H84Zm260-152h170v170H344V126Zm-174%2044h276%22%20fill%3D%22none%22%20stroke%3D%22%231d1d1f%22%20stroke-width%3D%2212%22%20stroke-linecap%3D%22round%22%20stroke-linejoin%3D%22round%22%20opacity%3D%22.34%22%2F%3E%3Ccircle%20cx%3D%22190%22%20cy%3D%2296%22%20r%3D%2220%22%20fill%3D%22%230071e3%22%2F%3E%3Ccircle%20cx%3D%22296%22%20cy%3D%22278%22%20r%3D%2220%22%20fill%3D%22%230071e3%22%2F%3E%3Ccircle%20cx%3D%22514%22%20cy%3D%22126%22%20r%3D%2218%22%20fill%3D%22%230071e3%22%2F%3E%3Ctext%20x%3D%2242%22%20y%3D%2258%22%20fill%3D%22%231d1d1f%22%20font-family%3D%22-apple-system%2CBlinkMacSystemFont%2CSegoe%20UI%2CArial%2Csans-serif%22%20font-size%3D%2224%22%20font-weight%3D%22700%22%3ESpectroscopy%3C%2Ftext%3E%3Ctext%20x%3D%2242%22%20y%3D%22355%22%20fill%3D%22%231d1d1f%22%20font-family%3D%22-apple-system%2CBlinkMacSystemFont%2CSegoe%20UI%2CArial%2Csans-serif%22%20font-size%3D%2236%22%20font-weight%3D%22800%22%3EAromatic%20substitution%20patter%3C%2Ftext%3E%3Ctext%20x%3D%2242%22%20y%3D%22388%22%20fill%3D%22%236e6e73%22%20font-family%3D%22-apple-system%2CBlinkMacSystemFont%2CSegoe%20UI%2CArial%2Csans-serif%22%20font-size%3D%2220%22%20font-weight%3D%22600%22%3EAromatic%20structure%3C%2Ftext%3E%3C%2Fsvg%3E',
  '{"id":"aromatic-substitution-pattern","title":"Aromatic substitution pattern screen","family":"Aromatic structure","confidence":66,"question":"Can the aromatic region support a substituted benzene pattern?","signals":[{"technique":"1H NMR","signal":"6.8-8.1 ppm multiplets","interpretation":"Aromatic protons","strength":"supporting"},{"technique":"13C NMR","signal":"110-150 ppm","interpretation":"Aromatic carbon environments","strength":"supporting"},{"technique":"1H NMR","signal":"integration pattern","interpretation":"May constrain substitution count","strength":"moderate"}],"conclusion":"The spectra support an aromatic ring but substitution pattern needs coupling analysis or 2D NMR.","missing":"COSY/HSQC/HMBC or authentic reference comparison."}',
  'spectroscopy spectroscopy aromatic substitution pattern screen aromatic structure can the aromatic region support a substituted benzene pattern the spectra support an aromatic ring but substitution pattern needs coupling analysis or 2d nmr. aromatic structure question can the aromatic region support a substituted benzene pattern signals 1h nmr 6.8-8.1 ppm multiplets aromatic protons 13c nmr 110-150 ppm aromatic carbon environments 1h nmr integration pattern may constrain substitution count assignments conclusion the spectra support an aromatic ring but substitution pattern needs coupling analysis or 2d nmr.'
);
